type Item = { type: string };
type Step = { op: "quote"; items: Item[] };
type Input = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PREMIUM = 60;

const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const isBlockOfAlikeRunes = (items: Item[]): boolean =>
  items.length === COMPONENT_BLOCK_SIZE && items.every((item) => item.type === "rune");

const sumOfBasePremiums = (items: Item[]): number =>
  items.reduce((sum, item) => sum + BASE_PREMIUM_BY_TYPE[item.type], 0);

const basePremium = (items: Item[]): number =>
  isBlockOfAlikeRunes(items) ? COMPONENT_BLOCK_PREMIUM : sumOfBasePremiums(items);

const percentOf = (amount: number, percent: number): number =>
  (amount * percent) / 100;

const firstInsuranceSurcharge = (base: number): number =>
  Math.ceil(percentOf(base, FIRST_INSURANCE_SURCHARGE_PERCENT));

const quotePremium = (items: Item[]): number => {
  const base = basePremium(items);
  return base + firstInsuranceSurcharge(base) + PROCESSING_FEE;
};

const executeStep = ({ items }: Step) => ({ premium: quotePremium(items) });

export const run = (input: unknown): unknown => {
  const { steps } = input as Input;
  return { results: steps.map(executeStep) };
};

