    expect(out).toEqual({ results: [{ premium: 5 }] });
  });

  // --- Base premiums per main item type ---
  it("quote for a single plain sword (new customer, 1st contract) → 100 base + 10 first-ins + 5 fee = 115 G", () => {
    const out = run({ customer: { yearsWithMHPCO: 0 }, steps: [{ op: "quote", items: [{ type: "sword" }] }] });
    expect(out).toEqual({ results: [{ premium: 115 }] });
  });
  it("quote for a single plain amulet (new customer, 1st contract) → 60 base + 6 first-ins + 5 fee = 71 G", () => {
    const out = run({ customer: { yearsWithMHPCO: 0 }, steps: [{ op: "quote", items: [{ type: "amulet" }] }] });
    expect(out).toEqual({ results: [{ premium: 71 }] });
  });
  it("quote for a single plain staff (new customer, 1st contract) → 80 base + 8 first-ins + 5 fee = 93 G", () => {
    const out = run({ customer: { yearsWithMHPCO: 0 }, steps: [{ op: "quote", items: [{ type: "staff" }] }] });
    expect(out).toEqual({ results: [{ premium: 93 }] });
  });
  it("quote for a single plain potion (new customer, 1st contract) → 40 base + 4 first-ins + 5 fee = 49 G", () => {
    const out = run({ customer: { yearsWithMHPCO: 0 }, steps: [{ op: "quote", items: [{ type: "potion" }] }] });
    expect(out).toEqual({ results: [{ premium: 49 }] });
  });

  // --- Components base premium (per-component default) ---
  it("quote for 2 runes (new customer, 1st contract) → 50 base + 5 first-ins + 5 fee = 60 G", () => {
    const out = run({ customer: { yearsWithMHPCO: 0 }, steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }] });
    expect(out).toEqual({ results: [{ premium: 60 }] });
  });

  // --- Building block of 3 alike components ---
  it("quote for 3 runes (block) (new customer, 1st contract) → 60 base + 6 first-ins + 5 fee = 71 G", () => {
    const out = run({ customer: { yearsWithMHPCO: 0 }, steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }] });
    expect(out).toEqual({ results: [{ premium: 71 }] });
  });
  it("quote for 4 runes (no block) → 100 base + 10 first-ins + 5 fee = 115 G", () => {
    const out = run({ customer: { yearsWithMHPCO: 0 }, steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }] }] });
    expect(out).toEqual({ results: [{ premium: 115 }] });
  });
  it("quote for 7 runes (no block — block requires exactly 3) → 175 base + 18 first-ins + 5 fee = 198 G", () => {
    const out = run({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: Array(7).fill({ type: "rune" }) }],
    });
    expect(out).toEqual({ results: [{ premium: 198 }] });
  });

  // --- 'Alike' components clarified by type ---
  it("quote for 2 runes + 1 moonstone (no block: different types) → 75 base + 8 first-ins + 5 fee = 88 G", () => {
    const out = run({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }] }],
    });
    expect(out).toEqual({ results: [{ premium: 88 }] });
  });
  it("quote for 3 runes + 3 moonstones (two separate blocks) → 120 base + 12 first-ins + 5 fee = 137 G", () => {
    const out = run({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [
        { type: "rune" }, { type: "rune" }, { type: "rune" },
        { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" },
      ] }],
    });
    expect(out).toEqual({ results: [{ premium: 137 }] });
  });

  // --- Single-modifier surcharges/discounts on a single item ---
  it.todo("cursed sword alone (new customer, 1st contract) → 100 base + 50 curse + 10 first-ins + 5 fee = 165 G");
  it.todo("high-enchantment sword (enchantment 5) alone (new customer, 1st contract) → 100 + 30 + 10 + 5 = 145 G");
  it.todo("sword with enchantment 4 alone (new customer, 1st contract) → no high-ench surcharge → 115 G");

  // --- Modifier thresholds ---
  it.todo("customer with exactly 2 years gets loyalty discount (plain sword, 1st contract) → 100 - 20 + 10 + 5 = 95 G");
  it.todo("cursed sword with exactly enchantment 5 gets both surcharges → 100 + 50 + 30 + 10 + 5 = 195 G");

  // --- Multi-item policy & modifier scope ---
  it.todo("cursed sword + plain amulet (new customer, 1st contract) → 100+60 base, cursed adds 50 (of sword only), first-ins 10% of policy total → 160 + 50 + 16 + 5 = 231 G");

  // --- Follow-up contract discount (15% on each contract after first) ---
  it.todo("second quote in scenario: cursed sword + plain amulet, 0 years → first ins still 10%, follow-up 15% off policy total");

  // --- Integration examples ---
  it.todo("newcomer cursed sword (0 years, no prior): 100 + 50 + 10 + 5 = 165 G");
  it.todo("long-standing customer's 2nd contract, cursed enchantment-7 sword (3 years): 100 + 50 + 30 - 20 + 10 - 15 + 5 = 160 G");

  // --- Rounding in MHPCO's favor ---
  it.todo("premium calculation yielding 197.5 G → final premium 198 G (rounded up)");

  // --- Claim: basic deductible & standard reimbursement ---
  it.todo("steel sword enchantment 3, damage 500 → payout 400 (500 - 100 deductible)");
  it.todo("damage to a rune (250 G), damage 200 → payout 100 (200 - 100 deductible)");

  // --- Claim: high-enchantment 50% clause ---
  it.todo("steel sword enchantment 9, damage 1000 → payout 400 (50% then deductible: 500 - 100)");

  // --- Claim: dragon material full reimbursement ---
  it.todo("dragon-material sword enchantment 5, damage 800 → payout 700 (full minus deductible)");

  // --- Claim: dragon + high enchantment combined (50% wins) ---
  it.todo("dragon-material sword enchantment 8, damage 1000 → payout 400 (high-ench applies first then deductible)");
  it.todo("dragon-material sword enchantment 9, damage 1000 → payout 400 (50% rule wins, then deductible)");

  // --- Claim: deductible per damage event ---
  it.todo("dragon attack damages insured sword 500 and amulet 300 → payout 600 (deductible applies once per damaged item)");

  // --- Multiple items of same type ---
  it.todo("policy with two swords: insurance sum 2000 G, cap 4000 G; two sword damage entries each get own deductible");
  it.todo("claim with more sword damages than swords insured → CLI exits non-zero (claim rejected)");

  // --- Cap exhaustion ---
  it.todo("sword + amulet policy → insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword cap is 2000 G (based on unmodified insurance value, premium modifiers do not raise cap)");
  it.todo("sword + 3 runes block: insurance sum 1750 G (block discount affects premium only, not insurance sum)");
  it.todo("sword (cap 2000): claim 1500 → payout 1400, remainingCap 600; second claim 1500 → payout 600, remainingCap 0");

  // --- Rounding payout ---
  it.todo("payout calculation yielding 350.5 G → final payout 350 G (rounded down)");

  // --- Error cases ---
  it.todo("quote with unknown item type (e.g. broomstick) → CLI exits non-zero with error to stderr");
  it.todo("claim references damage entry whose item is not in policy → CLI exits non-zero");
  it.todo("claim contains damage entry with negative amount → CLI exits non-zero");
});

type Item = { type: string };
type Step = { op: "quote"; items: Item[] };
type Input = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PREMIUM = 60;

const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

const groupBaseAmount = (type: string, count: number): number => {
  if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) {
    return COMPONENT_BLOCK_PREMIUM;
  }
  return count * BASE_PREMIUM_BY_TYPE[type];
};

const countByType = (items: Item[]): Map<string, number> =>
  items.reduce(
    (counts, { type }) => counts.set(type, (counts.get(type) ?? 0) + 1),
    new Map<string, number>(),
  );

const basePremium = (items: Item[]): number =>
  Array.from(countByType(items)).reduce(
    (total, [type, count]) => total + groupBaseAmount(type, count),
    0,
  );

const percentOf = (amount: number, percent: number): number =>
  (amount * percent) / 100;

const firstInsuranceSurcharge = (base: number): number =>
  Math.ceil(percentOf(base, FIRST_INSURANCE_SURCHARGE_PERCENT));

const quotePremium = (items: Item[]): number => {
  const base = basePremium(items);
  return base + firstInsuranceSurcharge(base) + PROCESSING_FEE;
};

const executeStep = ({ items }: Step) => ({ premium: quotePremium(items) });

export const run = (input: unknown): unknown => {
  const { steps } = input as Input;
  return { results: steps.map(executeStep) };
};

