  const base = basePremium(items);
  return (
    base
    + itemSurcharges(items)
    - loyaltyDiscount(base, customer)
    + firstInsuranceSurcharge(base)
    + PROCESSING_FEE
  );
};

const executeStep = (customer: Customer) => ({ items }: Step) => ({
  premium: quotePremium(items, customer),
});

export const run = (input: unknown): unknown => {
  const { customer, steps } = input as Input;
  return { results: steps.map(executeStep(customer)) };
};

